changeSet.sql:
CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE IF NOT EXISTS app.users (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    email text UNIQUE NOT NULL,
    display_name text,
    created_at timestamptz NOT NULL DEFAULT now()
);

INSERT INTO app.users (id, email, display_name)
VALUES (
    '00000000-0000-0000-0000-000000000001',
    'dev@notebook.local',
    'Dev User'
)
ON CONFLICT (id) DO NOTHING;

CREATE TABLE IF NOT EXISTS app.notebooks (
    id uuid PRIMARY KEY,
    owner_id uuid NOT NULL REFERENCES app.users(id) ON DELETE CASCADE,
    title text NOT NULL,
    format_version int NOT NULL DEFAULT 1,
    cells jsonb NOT NULL DEFAULT '[]'::jsonb,
    created_at timestamptz NOT NULL DEFAULT now(),
    updated_at timestamptz NOT NULL DEFAULT now(),
    deleted_at timestamptz
);

CREATE INDEX IF NOT EXISTS notebooks_owner_updated_idx
    ON app.notebooks(owner_id, updated_at DESC)
    WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS notebooks_owner_active_idx
    ON app.notebooks(owner_id)
    WHERE deleted_at IS NULL;
